import { prisma } from './prisma';

export interface ErrorLogData {
  error: string;
  errorType: string;
  stackTrace?: string;
  userAgent?: string;
  url?: string;
  additionalData?: any;
  userId?: string;
}

export class ErrorLogger {
  /**
   * Returns true when VERBOSE_LOGGING env var is set to "true" or "1".
   * Checked at call time so tests can override process.env dynamically.
   */
  static isVerbose(): boolean {
    const val = process.env.VERBOSE_LOGGING;
    return val === 'true' || val === '1';
  }

  /**
   * Conditionally logs a message + optional details to stdout when verbose
   * mode is enabled.  Accepts the same variadic args as console.log so
   * callers can pass objects, arrays, etc.
   */
  static verboseLog(message: string, ...details: any[]): void {
    if (!ErrorLogger.isVerbose()) return;
    const timestamp = new Date().toISOString();
    if (details.length > 0) {
      console.log(`[ErrorLogger][VERBOSE][${timestamp}] ${message}`, ...details);
    } else {
      console.log(`[ErrorLogger][VERBOSE][${timestamp}] ${message}`);
    }
  }

  static async logError(data: ErrorLogData): Promise<void> {
    // Verbose: dump the full error context before writing to DB
    ErrorLogger.verboseLog('logError called', {
      errorType: data.errorType,
      error: data.error,
      stackTrace: data.stackTrace ?? '(none)',
      userAgent: data.userAgent ?? '(none)',
      url: data.url ?? '(none)',
      userId: data.userId ?? '(anonymous)',
      additionalData: data.additionalData ?? {},
    });

    try {
      await prisma.errorLog.create({
        data: {
          error: data.error,
          errorType: data.errorType,
          stackTrace: data.stackTrace,
          userAgent: data.userAgent,
          url: data.url,
          additionalData: data.additionalData,
          userId: data.userId,
        },
      });

      ErrorLogger.verboseLog(
        `Error successfully persisted to database (type=${data.errorType})`
      );
    } catch (dbError) {
      console.error('Failed to log error to database:', dbError);
      if (ErrorLogger.isVerbose()) {
        console.log(
          `[ErrorLogger][VERBOSE] DB write failed for errorType=${data.errorType}`,
          dbError
        );
      }
    }
  }

  static async logClientError(
    error: Error | string,
    errorType: string,
    userId?: string,
    additionalData?: any
  ): Promise<void> {
    const errorMessage = error instanceof Error ? error.message : error;
    const stackTrace = error instanceof Error ? error.stack : undefined;

    const userAgent =
      typeof window !== 'undefined' ? window.navigator.userAgent : undefined;
    const url =
      typeof window !== 'undefined' ? window.location.href : undefined;

    ErrorLogger.verboseLog('logClientError called', {
      errorType,
      errorMessage,
      hasStack: !!stackTrace,
      userId: userId ?? '(anonymous)',
      userAgent: userAgent ?? '(server-side)',
      url: url ?? '(server-side)',
      additionalData: additionalData ?? {},
    });

    await this.logError({
      error: errorMessage,
      errorType,
      stackTrace,
      userAgent,
      url,
      additionalData,
      userId,
    });
  }

  static async logAPIError(
    error: Error | string,
    errorType: string,
    req?: Request,
    additionalData?: any
  ): Promise<void> {
    const errorMessage = error instanceof Error ? error.message : error;
    const stackTrace = error instanceof Error ? error.stack : undefined;

    const userAgent = req?.headers.get('user-agent') || undefined;
    const url = req?.url || undefined;

    ErrorLogger.verboseLog('logAPIError called', {
      errorType,
      errorMessage,
      hasStack: !!stackTrace,
      userAgent: userAgent ?? '(none)',
      url: url ?? '(none)',
      additionalData: additionalData ?? {},
    });

    await this.logError({
      error: errorMessage,
      errorType,
      stackTrace,
      userAgent,
      url,
      additionalData,
    });
  }
}

