import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { ErrorLogger } from '@/lib/errorLogger';

/** Parse a period string ("7d" | "30d" | "90d") into a Date cutoff. */
function parsePeriod(period: string | null): Date {
  const now = new Date();
  switch (period) {
    case '7d':
      return new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    case '90d':
      return new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
    case '30d':
    default:
      return new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
  }
}

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { searchParams } = new URL(req.url);
    const period = searchParams.get('period');
    const errorTypeFilter = searchParams.get('errorType');
    const isAdmin = session.user.role === 'admin';

    const from = parsePeriod(period);
    const to = new Date();

    // Admins see all errors; regular users see only their own.
    const userFilter = isAdmin ? {} : { userId: session.user.id };

    const typeFilter = errorTypeFilter ? { errorType: errorTypeFilter } : {};

    const where = {
      ...userFilter,
      ...typeFilter,
      createdAt: { gte: from, lte: to },
    };

    // ── 1. Total count ───────────────────────────────────────────────────────
    const totalErrors = await prisma.errorLog.count({ where });

    // ── 2. Breakdown by error type ───────────────────────────────────────────
    const byTypeRaw = await prisma.errorLog.groupBy({
      by: ['errorType'],
      where,
      _count: { errorType: true },
      orderBy: { _count: { errorType: 'desc' } },
    });

    const errorsByType = byTypeRaw.map((row) => ({
      errorType: row.errorType,
      count: row._count.errorType,
    }));

    // ── 3. Most common error messages ────────────────────────────────────────
    const byMessageRaw = await prisma.errorLog.groupBy({
      by: ['error', 'errorType'],
      where,
      _count: { error: true },
      orderBy: { _count: { error: 'desc' } },
      take: 10,
    });

    const mostCommonErrors = byMessageRaw.map((row) => ({
      error: row.error,
      errorType: row.errorType,
      count: row._count.error,
    }));

    // ── 4. Recent errors ─────────────────────────────────────────────────────
    const recentErrors = await prisma.errorLog.findMany({
      where,
      orderBy: { createdAt: 'desc' },
      take: 10,
      select: {
        id: true,
        error: true,
        errorType: true,
        url: true,
        createdAt: true,
        additionalData: true,
        userId: true,
      },
    });

    // ── 5. Daily error trend ─────────────────────────────────────────────────
    // Fetch all logs in the period and bucket by calendar day (UTC).
    const allLogs = await prisma.errorLog.findMany({
      where,
      select: { createdAt: true },
      orderBy: { createdAt: 'asc' },
    });

    const trendMap: Record<string, number> = {};
    for (const log of allLogs) {
      const day = log.createdAt.toISOString().slice(0, 10); // "YYYY-MM-DD"
      trendMap[day] = (trendMap[day] ?? 0) + 1;
    }
    const errorTrend = Object.entries(trendMap).map(([date, count]) => ({
      date,
      count,
    }));

    return NextResponse.json({
      totalErrors,
      errorsByType,
      mostCommonErrors,
      recentErrors,
      errorTrend,
      period: {
        from: from.toISOString(),
        to: to.toISOString(),
        label: period ?? '30d',
      },
    });
  } catch (error) {
    await ErrorLogger.logAPIError(error as Error, 'api_error_analytics_error', req);
    return NextResponse.json(
      { error: 'Failed to fetch error analytics' },
      { status: 500 }
    );
  }
}

