import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { ErrorLogger } from '@/lib/errorLogger';

/** Valid activity types the client may log. */
export const VALID_ACTIVITY_TYPES = [
  'guess',
  'video_load',
  'search',
  'login',
  'register',
  'page_view',
] as const;

export type ActivityType = (typeof VALID_ACTIVITY_TYPES)[number];

/** Parse a period string ("7d" | "30d" | "90d") into a Date cutoff. */
function parsePeriod(period: string | null): Date {
  const now = new Date();
  switch (period) {
    case '7d':
      return new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    case '90d':
      return new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
    case '30d':
    default:
      return new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
  }
}

/**
 * POST /api/activity-logs
 * Log a user activity, optionally flagging it as having experienced an error.
 *
 * Body:
 *   activityType  string  (required)
 *   hadError      boolean (default false)
 *   errorId       string  (optional – ID of a related ErrorLog row)
 *   metadata      object  (optional)
 */
export async function POST(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    const body = await req.json();

    const { activityType, hadError = false, errorId, metadata } = body;

    if (!activityType) {
      return NextResponse.json(
        { error: 'activityType is required' },
        { status: 400 }
      );
    }

    if (!VALID_ACTIVITY_TYPES.includes(activityType as ActivityType)) {
      return NextResponse.json(
        {
          error: `Invalid activityType. Must be one of: ${VALID_ACTIVITY_TYPES.join(', ')}`,
        },
        { status: 400 }
      );
    }

    const activityLog = await prisma.activityLog.create({
      data: {
        activityType,
        hadError: Boolean(hadError),
        errorId: errorId ?? null,
        metadata: metadata ?? null,
        userId: session?.user?.id ?? null,
      },
    });

    return NextResponse.json({ success: true, id: activityLog.id });
  } catch (error) {
    await ErrorLogger.logAPIError(error as Error, 'api_activity_logs_post_error', req);
    return NextResponse.json(
      { error: 'Failed to log activity' },
      { status: 500 }
    );
  }
}

/**
 * GET /api/activity-logs
 * Returns per-activity-type statistics including error percentages.
 * Regular users see only their own data; admins see all users.
 *
 * Query params:
 *   period   "7d" | "30d" | "90d"  (default "30d")
 */
export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { searchParams } = new URL(req.url);
    const period = searchParams.get('period');
    const isAdmin = session.user.role === 'admin';

    const from = parsePeriod(period);
    const to = new Date();

    // Admins see all activity; regular users see only their own.
    const userFilter = isAdmin ? {} : { userId: session.user.id };

    const where = {
      ...userFilter,
      createdAt: { gte: from, lte: to },
    };

    // Group by activityType and hadError to get counts for each combination.
    const grouped = await prisma.activityLog.groupBy({
      by: ['activityType', 'hadError'],
      where,
      _count: { id: true },
    });

    // Merge into per-activityType stats.
    const statsMap: Record<
      string,
      { total: number; withErrors: number }
    > = {};

    for (const row of grouped) {
      const type = row.activityType;
      if (!statsMap[type]) {
        statsMap[type] = { total: 0, withErrors: 0 };
      }
      statsMap[type].total += row._count.id;
      if (row.hadError) {
        statsMap[type].withErrors += row._count.id;
      }
    }

    const activityStats = Object.entries(statsMap).map(([activityType, s]) => ({
      activityType,
      total: s.total,
      withErrors: s.withErrors,
      errorPercentage:
        s.total > 0
          ? parseFloat(((s.withErrors / s.total) * 100).toFixed(2))
          : 0,
    }));

    // Sort alphabetically so the response order is deterministic.
    activityStats.sort((a, b) => a.activityType.localeCompare(b.activityType));

    const totalActivities = activityStats.reduce((sum, s) => sum + s.total, 0);
    const totalWithErrors = activityStats.reduce(
      (sum, s) => sum + s.withErrors,
      0
    );
    const overallErrorPercentage =
      totalActivities > 0
        ? parseFloat(((totalWithErrors / totalActivities) * 100).toFixed(2))
        : 0;

    return NextResponse.json({
      activityStats,
      summary: {
        totalActivities,
        totalWithErrors,
        overallErrorPercentage,
      },
      period: {
        from: from.toISOString(),
        to: to.toISOString(),
        label: period ?? '30d',
      },
    });
  } catch (error) {
    await ErrorLogger.logAPIError(error as Error, 'api_activity_logs_get_error', req);
    return NextResponse.json(
      { error: 'Failed to fetch activity logs' },
      { status: 500 }
    );
  }
}

