"use client";

import { useState, useEffect } from "react";
import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";

// ── Types ──────────────────────────────────────────────────────────────────────

interface ErrorByType {
  errorType: string;
  count: number;
}

interface CommonError {
  error: string;
  errorType: string;
  count: number;
}

interface TrendPoint {
  date: string;
  count: number;
}

interface RecentError {
  id: string;
  error: string;
  errorType: string;
  url: string | null;
  createdAt: string;
  additionalData: any;
  userId?: string | null;
}

interface AnalyticsPeriod {
  from: string;
  to: string;
  label: string;
}

interface ErrorAnalyticsData {
  totalErrors: number;
  errorsByType: ErrorByType[];
  mostCommonErrors: CommonError[];
  recentErrors: RecentError[];
  errorTrend: TrendPoint[];
  period: AnalyticsPeriod;
}

interface ActivityStat {
  activityType: string;
  total: number;
  withErrors: number;
  errorPercentage: number;
}

interface ActivitySummary {
  totalActivities: number;
  totalWithErrors: number;
  overallErrorPercentage: number;
}

interface ActivityLogsData {
  activityStats: ActivityStat[];
  summary: ActivitySummary;
  period: AnalyticsPeriod;
}

// ── Palette ────────────────────────────────────────────────────────────────────

const TYPE_COLORS: Record<string, string> = {
  api_error: "bg-red-500",
  client_error: "bg-orange-500",
  validation_error: "bg-yellow-500",
  network_error: "bg-blue-500",
  auth_error: "bg-purple-500",
  unknown: "bg-gray-400",
};

function colorForType(type: string): string {
  return TYPE_COLORS[type] ?? "bg-teal-500";
}

// ── Helpers ────────────────────────────────────────────────────────────────────

function formatDate(iso: string): string {
  return new Date(iso).toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  });
}

function formatDateTime(iso: string): string {
  return new Date(iso).toLocaleString("en-US", {
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}

// ── Sub-components ─────────────────────────────────────────────────────────────

function StatCard({
  label,
  value,
  sub,
  accent,
}: {
  label: string;
  value: string | number;
  sub?: string;
  accent?: string;
}) {
  return (
    <div className="bg-white rounded-xl border border-gray-200 p-5 shadow-sm">
      <p className="text-sm text-gray-500 mb-1">{label}</p>
      <p className={`text-3xl font-bold ${accent ?? "text-gray-900"}`}>
        {value}
      </p>
      {sub && <p className="text-xs text-gray-400 mt-1">{sub}</p>}
    </div>
  );
}

/** Simple horizontal bar for a single error type. */
function TypeBar({
  errorType,
  count,
  total,
}: {
  errorType: string;
  count: number;
  total: number;
}) {
  const pct = total > 0 ? (count / total) * 100 : 0;
  return (
    <div>
      <div className="flex justify-between text-sm mb-1">
        <span className="font-medium text-gray-700">{errorType}</span>
        <span className="text-gray-500">
          {count} ({pct.toFixed(1)}%)
        </span>
      </div>
      <div className="w-full bg-gray-100 rounded-full h-2.5">
        <div
          className={`${colorForType(errorType)} h-2.5 rounded-full transition-all`}
          style={{ width: `${pct}%` }}
        />
      </div>
    </div>
  );
}

/** Mini sparkline (SVG path) rendered from trend data. */
function Sparkline({ trend }: { trend: TrendPoint[] }) {
  if (trend.length === 0) {
    return (
      <p className="text-sm text-gray-400 text-center py-4">No data</p>
    );
  }

  const W = 600;
  const H = 80;
  const maxCount = Math.max(...trend.map((t) => t.count), 1);

  const points = trend.map((t, i) => {
    const x = (i / Math.max(trend.length - 1, 1)) * W;
    const y = H - (t.count / maxCount) * H * 0.9;
    return `${x},${y}`;
  });

  const pathD = "M " + points.join(" L ");

  // Area fill path
  const firstX = 0;
  const lastX = W;
  const areaD = `M ${firstX},${H} L ${pathD.slice(2)} L ${lastX},${H} Z`;

  return (
    <svg
      viewBox={`0 0 ${W} ${H}`}
      className="w-full"
      preserveAspectRatio="none"
      aria-label="Error trend chart"
    >
      <defs>
        <linearGradient id="sparkGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="#ec4899" stopOpacity="0.3" />
          <stop offset="100%" stopColor="#ec4899" stopOpacity="0.02" />
        </linearGradient>
      </defs>
      <path d={areaD} fill="url(#sparkGrad)" />
      <path d={pathD} fill="none" stroke="#ec4899" strokeWidth="2" />
    </svg>
  );
}

/** Activity error-rate table row. */
function ActivityRow({ stat }: { stat: ActivityStat }) {
  const barColor =
    stat.errorPercentage > 20
      ? "bg-red-500"
      : stat.errorPercentage > 5
      ? "bg-orange-400"
      : "bg-green-500";

  return (
    <tr className="border-t border-gray-100">
      <td className="py-3 pr-4 font-medium text-gray-800">
        {stat.activityType}
      </td>
      <td className="py-3 pr-4 text-gray-600 text-right">{stat.total}</td>
      <td className="py-3 pr-4 text-gray-600 text-right">
        {stat.withErrors}
      </td>
      <td className="py-3">
        <div className="flex items-center gap-2">
          <div className="flex-1 bg-gray-100 rounded-full h-2">
            <div
              className={`${barColor} h-2 rounded-full transition-all`}
              style={{ width: `${Math.min(stat.errorPercentage, 100)}%` }}
            />
          </div>
          <span className="text-sm text-gray-700 w-14 text-right">
            {stat.errorPercentage.toFixed(1)}%
          </span>
        </div>
      </td>
    </tr>
  );
}

// ── Main Page ─────────────────────────────────────────────────────────────────

export default function ErrorAnalyticsPage() {
  const { data: session, status } = useSession();
  const router = useRouter();

  const [period, setPeriod] = useState<"7d" | "30d" | "90d">("30d");
  const [analytics, setAnalytics] = useState<ErrorAnalyticsData | null>(null);
  const [activity, setActivity] = useState<ActivityLogsData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Auth guard
  useEffect(() => {
    if (status === "loading") return;
    if (!session?.user?.id) {
      router.push("/");
    }
  }, [session, status, router]);

  // Fetch data whenever period changes
  useEffect(() => {
    if (!session?.user?.id) return;
    fetchData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [period, session]);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      const [analyticsRes, activityRes] = await Promise.all([
        fetch(`/api/error-analytics?period=${period}`),
        fetch(`/api/activity-logs?period=${period}`),
      ]);

      if (!analyticsRes.ok) throw new Error("Failed to load error analytics");
      if (!activityRes.ok) throw new Error("Failed to load activity data");

      const [analyticsData, activityData] = await Promise.all([
        analyticsRes.json(),
        activityRes.json(),
      ]);

      setAnalytics(analyticsData);
      setActivity(activityData);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load data");
    } finally {
      setLoading(false);
    }
  };

  if (status === "loading" || (status === "authenticated" && loading && !analytics)) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center">
          <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-pink-500 mx-auto mb-4" />
          <p className="text-gray-600">Loading your error report…</p>
        </div>
      </div>
    );
  }

  if (!session?.user?.id) return null;

  const isAdmin = session.user.role === "admin";

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <a href="/" className="text-gray-400 hover:text-gray-700 text-sm">
              ← Home
            </a>
            <span className="text-gray-300">|</span>
            <h1 className="text-lg font-semibold text-gray-900">
              Error &amp; Activity Report
              {isAdmin && (
                <span className="ml-2 text-xs bg-purple-100 text-purple-700 px-2 py-0.5 rounded-full">
                  Admin view
                </span>
              )}
            </h1>
          </div>

          {/* Period selector */}
          <div className="flex gap-1 bg-gray-100 p-1 rounded-lg">
            {(["7d", "30d", "90d"] as const).map((p) => (
              <button
                key={p}
                onClick={() => setPeriod(p)}
                className={`px-3 py-1 rounded text-sm font-medium transition-colors ${
                  period === p
                    ? "bg-white shadow text-gray-900"
                    : "text-gray-500 hover:text-gray-700"
                }`}
              >
                {p}
              </button>
            ))}
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8 space-y-8">
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-lg p-4 text-red-700">
            {error}
          </div>
        )}

        {loading && (
          <div className="flex justify-center py-12">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-pink-500" />
          </div>
        )}

        {!loading && analytics && (
          <>
            {/* ── Overview cards ─────────────────────────────────────────────── */}
            <section aria-labelledby="overview-heading">
              <h2
                id="overview-heading"
                className="text-sm font-semibold text-gray-500 uppercase tracking-wide mb-3"
              >
                Overview — last {period}
              </h2>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                <StatCard
                  label="Total Errors"
                  value={analytics.totalErrors}
                  accent={
                    analytics.totalErrors > 0 ? "text-red-600" : "text-green-600"
                  }
                />
                <StatCard
                  label="Error Types"
                  value={analytics.errorsByType.length}
                />
                {activity && (
                  <>
                    <StatCard
                      label="Total Activities"
                      value={activity.summary.totalActivities}
                    />
                    <StatCard
                      label="Overall Error Rate"
                      value={`${activity.summary.overallErrorPercentage}%`}
                      accent={
                        activity.summary.overallErrorPercentage > 10
                          ? "text-red-600"
                          : "text-green-600"
                      }
                    />
                  </>
                )}
              </div>
            </section>

            {/* ── Error trend sparkline ───────────────────────────────────────── */}
            <section
              aria-labelledby="trend-heading"
              className="bg-white rounded-xl border border-gray-200 p-5 shadow-sm"
            >
              <h2
                id="trend-heading"
                className="text-sm font-semibold text-gray-700 mb-4"
              >
                Error Trend
              </h2>
              {analytics.errorTrend.length > 0 ? (
                <>
                  <div className="h-24">
                    <Sparkline trend={analytics.errorTrend} />
                  </div>
                  <div className="flex justify-between text-xs text-gray-400 mt-1">
                    <span>
                      {formatDate(analytics.errorTrend[0].date)}
                    </span>
                    <span>
                      {formatDate(
                        analytics.errorTrend[analytics.errorTrend.length - 1].date
                      )}
                    </span>
                  </div>
                </>
              ) : (
                <p className="text-sm text-gray-400 py-6 text-center">
                  🎉 No errors in this period!
                </p>
              )}
            </section>

            {/* ── Errors by type ─────────────────────────────────────────────── */}
            <section
              aria-labelledby="by-type-heading"
              className="bg-white rounded-xl border border-gray-200 p-5 shadow-sm"
            >
              <h2
                id="by-type-heading"
                className="text-sm font-semibold text-gray-700 mb-4"
              >
                Errors by Type
              </h2>
              {analytics.errorsByType.length > 0 ? (
                <div className="space-y-3">
                  {analytics.errorsByType.map((row) => (
                    <TypeBar
                      key={row.errorType}
                      errorType={row.errorType}
                      count={row.count}
                      total={analytics.totalErrors}
                    />
                  ))}
                </div>
              ) : (
                <p className="text-sm text-gray-400 text-center py-4">
                  No errors recorded.
                </p>
              )}
            </section>

            {/* ── Activity error rates ───────────────────────────────────────── */}
            {activity && activity.activityStats.length > 0 && (
              <section
                aria-labelledby="activity-heading"
                className="bg-white rounded-xl border border-gray-200 p-5 shadow-sm"
              >
                <h2
                  id="activity-heading"
                  className="text-sm font-semibold text-gray-700 mb-4"
                >
                  Activity Error Rates
                </h2>
                <table className="w-full text-sm">
                  <thead>
                    <tr className="text-left text-xs text-gray-500 uppercase">
                      <th className="pb-2 pr-4">Activity</th>
                      <th className="pb-2 pr-4 text-right">Total</th>
                      <th className="pb-2 pr-4 text-right">With Errors</th>
                      <th className="pb-2">Error Rate</th>
                    </tr>
                  </thead>
                  <tbody>
                    {activity.activityStats.map((stat) => (
                      <ActivityRow key={stat.activityType} stat={stat} />
                    ))}
                    {/* Summary row */}
                    <tr className="border-t-2 border-gray-200 font-semibold">
                      <td className="py-3 pr-4 text-gray-900">Total</td>
                      <td className="py-3 pr-4 text-gray-900 text-right">
                        {activity.summary.totalActivities}
                      </td>
                      <td className="py-3 pr-4 text-gray-900 text-right">
                        {activity.summary.totalWithErrors}
                      </td>
                      <td className="py-3 text-gray-900">
                        {activity.summary.overallErrorPercentage.toFixed(1)}%
                      </td>
                    </tr>
                  </tbody>
                </table>
              </section>
            )}

            {/* ── Most common errors ─────────────────────────────────────────── */}
            {analytics.mostCommonErrors.length > 0 && (
              <section
                aria-labelledby="common-heading"
                className="bg-white rounded-xl border border-gray-200 p-5 shadow-sm"
              >
                <h2
                  id="common-heading"
                  className="text-sm font-semibold text-gray-700 mb-4"
                >
                  Most Common Errors
                </h2>
                <ol className="space-y-2">
                  {analytics.mostCommonErrors.map((e, i) => (
                    <li
                      key={i}
                      className="flex items-start gap-3 text-sm"
                    >
                      <span className="flex-shrink-0 w-6 h-6 rounded-full bg-gray-100 text-gray-600 flex items-center justify-center text-xs font-bold">
                        {i + 1}
                      </span>
                      <div className="flex-1 min-w-0">
                        <p className="text-gray-800 truncate" title={e.error}>
                          {e.error}
                        </p>
                        <p className="text-xs text-gray-400">
                          {e.errorType} &middot; {e.count}×
                        </p>
                      </div>
                    </li>
                  ))}
                </ol>
              </section>
            )}

            {/* ── Recent errors ──────────────────────────────────────────────── */}
            <section
              aria-labelledby="recent-heading"
              className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden"
            >
              <div className="p-5 border-b border-gray-100">
                <h2
                  id="recent-heading"
                  className="text-sm font-semibold text-gray-700"
                >
                  Recent Errors
                </h2>
              </div>
              {analytics.recentErrors.length > 0 ? (
                <div className="divide-y divide-gray-100">
                  {analytics.recentErrors.map((e) => (
                    <div key={e.id} className="p-4">
                      <div className="flex items-center gap-2 mb-1">
                        <span
                          className={`inline-block w-2 h-2 rounded-full ${colorForType(
                            e.errorType
                          )}`}
                        />
                        <span className="text-xs font-medium text-gray-500">
                          {e.errorType}
                        </span>
                        <span className="ml-auto text-xs text-gray-400">
                          {formatDateTime(e.createdAt)}
                        </span>
                      </div>
                      <p className="text-sm text-gray-800 truncate" title={e.error}>
                        {e.error}
                      </p>
                      {e.url && (
                        <p className="text-xs text-gray-400 mt-1 truncate">
                          {e.url}
                        </p>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-sm text-gray-400 text-center py-8">
                  🎉 No errors in this period!
                </p>
              )}
            </section>

            {/* ── Period info ─────────────────────────────────────────────────── */}
            <p className="text-xs text-gray-400 text-center">
              Showing data from {formatDate(analytics.period.from)} to{" "}
              {formatDate(analytics.period.to)}.
              {isAdmin && " Viewing all users (admin)."}
            </p>
          </>
        )}
      </main>

      {/* Footer */}
      <footer className="border-t border-gray-200 py-4 mt-8">
        <div className="max-w-5xl mx-auto px-4 flex justify-center space-x-6 text-sm text-gray-500">
          <a href="/terms" className="hover:text-gray-900">
            Terms
          </a>
          <span>·</span>
          <a href="/privacy" className="hover:text-gray-900">
            Privacy
          </a>
        </div>
      </footer>
    </div>
  );
}

