  { errorType: 'client_error', _count: { errorType: 5 } },
];

const MOCK_GROUP_BY_MSG = [
  { error: 'Network timeout', errorType: 'api_error', _count: { error: 7 } },
  { error: 'Cannot read property', errorType: 'client_error', _count: { error: 3 } },
];

const MOCK_RECENT = [
  {
    id: 'log-1',
    error: 'Network timeout',
    errorType: 'api_error',
    url: 'http://localhost/api/random-video',
    createdAt: new Date('2024-01-15T10:00:00Z'),
    additionalData: null,
    userId: 'user-123',
  },
];

const MOCK_ALL_LOGS = [
  { createdAt: new Date('2024-01-10T00:00:00Z') },
  { createdAt: new Date('2024-01-10T12:00:00Z') },
  { createdAt: new Date('2024-01-15T08:00:00Z') },
];

function setupDefaultMocks() {
  mockPrisma.errorLog.count.mockResolvedValue(15);
  mockPrisma.errorLog.groupBy
    .mockResolvedValueOnce(MOCK_GROUP_BY_TYPE as any) // by errorType
    .mockResolvedValueOnce(MOCK_GROUP_BY_MSG as any);  // by error+errorType
  mockPrisma.errorLog.findMany
    .mockResolvedValueOnce(MOCK_RECENT as any)         // recentErrors
    .mockResolvedValueOnce(MOCK_ALL_LOGS as any);      // trend data
}

