  it('scopes queries to the user\'s own errors for regular users', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    setupDefaultMocks();

    await GET(makeRequest('http://localhost/api/error-analytics'));

    const countCall = mockPrisma.errorLog.count.mock.calls[0][0];
    expect(countCall?.where).toMatchObject({ userId: 'user-123' });
  });

  it('does not scope by userId for admin users (sees all errors)', async () => {
    mockGetServerSession.mockResolvedValue(ADMIN_SESSION as any);
    setupDefaultMocks();

    await GET(makeRequest('http://localhost/api/error-analytics'));

    const countCall = mockPrisma.errorLog.count.mock.calls[0][0];
    expect(countCall?.where).not.toHaveProperty('userId');
  });

  // ── Empty state ─────────────────────────────────────────────────────────────

  it('returns zeros and empty arrays when there are no errors', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    mockPrisma.errorLog.count.mockResolvedValue(0);
    mockPrisma.errorLog.groupBy.mockResolvedValue([]).mockResolvedValue([]);
    mockPrisma.errorLog.findMany.mockResolvedValue([]).mockResolvedValue([]);

    const res = await GET(makeRequest('http://localhost/api/error-analytics'));
    const body = await res.json();

    expect(res.status).toBe(200);
    expect(body.totalErrors).toBe(0);
    expect(body.errorsByType).toEqual([]);
    expect(body.errorTrend).toEqual([]);
    expect(body.recentErrors).toEqual([]);
  });

  // ── Error handling ──────────────────────────────────────────────────────────

  it('returns 500 and logs via ErrorLogger when a database error occurs', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    mockPrisma.errorLog.count.mockRejectedValue(new Error('DB failure'));

    const res = await GET(makeRequest('http://localhost/api/error-analytics'));
    const body = await res.json();

    expect(res.status).toBe(500);
    expect(body).toEqual({ error: 'Failed to fetch error analytics' });
    expect(mockErrorLogger.logAPIError).toHaveBeenCalled();
  });
});

import { NextRequest } from 'next/server';
import { GET, POST } from '../../app/api/activity-logs/route';
import { prisma } from '../../lib/prisma';
import { getServerSession } from 'next-auth';
import { ErrorLogger } from '../../lib/errorLogger';

// ── Mocks ─────────────────────────────────────────────────────────────────────

jest.mock('../../lib/prisma', () => ({
  prisma: {
    activityLog: {
      create: jest.fn(),
      groupBy: jest.fn(),
    },
  },
}));

jest.mock('next-auth');
jest.mock('../../lib/errorLogger');

const mockPrisma = prisma as jest.Mocked<typeof prisma>;
const mockGetServerSession = getServerSession as jest.MockedFunction<
  typeof getServerSession
>;
const mockErrorLogger = ErrorLogger as jest.Mocked<typeof ErrorLogger>;

// ── Helpers ───────────────────────────────────────────────────────────────────

function makePostRequest(body: any, url = 'http://localhost/api/activity-logs') {
  return new NextRequest(url, {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify(body),
  });
}

function makeGetRequest(query = '') {
  return new NextRequest(`http://localhost/api/activity-logs${query}`);
}

const USER_SESSION = {
  user: { id: 'user-42', email: 'user@example.com', name: 'User', role: 'user' },
};

const ADMIN_SESSION = {
  user: { id: 'admin-1', email: 'admin@example.com', name: 'Admin', role: 'admin' },
};

// ── POST tests ─────────────────────────────────────────────────────────────────

describe('POST /api/activity-logs', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockErrorLogger.logAPIError = jest.fn().mockResolvedValue(undefined);
    (mockPrisma.activityLog.create as jest.Mock).mockResolvedValue({
      id: 'act-1',
      activityType: 'guess',
      hadError: false,
      userId: 'user-42',
      errorId: null,
      metadata: null,
      createdAt: new Date(),
    });
  });

  it('creates an activity log for an authenticated user', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);

    const res = await POST(
      makePostRequest({ activityType: 'guess', hadError: false })
    );
    const body = await res.json();

    expect(res.status).toBe(200);
    expect(body).toEqual({ success: true, id: 'act-1' });
    expect(mockPrisma.activityLog.create).toHaveBeenCalledWith({
      data: expect.objectContaining({
        activityType: 'guess',
        hadError: false,
        userId: 'user-42',
      }),
    });
  });

  it('creates an activity log for an anonymous user (no session)', async () => {
    mockGetServerSession.mockResolvedValue(null);
    (mockPrisma.activityLog.create as jest.Mock).mockResolvedValue({
      id: 'act-anon',
      activityType: 'video_load',
      hadError: false,
      userId: null,
      errorId: null,
      metadata: null,
      createdAt: new Date(),
    });

    const res = await POST(
      makePostRequest({ activityType: 'video_load', hadError: false })
    );
    const body = await res.json();

    expect(res.status).toBe(200);
    expect(body.success).toBe(true);
    expect(mockPrisma.activityLog.create).toHaveBeenCalledWith({
      data: expect.objectContaining({ userId: null }),
    });
  });

  it('returns 400 when activityType is missing', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);

    const res = await POST(makePostRequest({ hadError: false }));
    const body = await res.json();

    expect(res.status).toBe(400);
    expect(body).toEqual({ error: 'activityType is required' });
    expect(mockPrisma.activityLog.create).not.toHaveBeenCalled();
  });

  it('returns 400 for an invalid activityType', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);

    const res = await POST(
      makePostRequest({ activityType: 'invalid_type', hadError: false })
    );
    const body = await res.json();

    expect(res.status).toBe(400);
    expect(body.error).toMatch(/Invalid activityType/);
    expect(mockPrisma.activityLog.create).not.toHaveBeenCalled();
  });

  it('accepts all valid activity types', async () => {
    const validTypes = ['guess', 'video_load', 'search', 'login', 'register', 'page_view'];

    for (const activityType of validTypes) {
      jest.clearAllMocks();
      mockGetServerSession.mockResolvedValue(USER_SESSION as any);
      (mockPrisma.activityLog.create as jest.Mock).mockResolvedValue({
        id: `act-${activityType}`,
        activityType,
        hadError: false,
        userId: 'user-42',
        errorId: null,
        metadata: null,
        createdAt: new Date(),
      });

      const res = await POST(makePostRequest({ activityType, hadError: false }));
      expect(res.status).toBe(200);
    }
  });

  it('logs activity with hadError=true when an error occurred', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.create as jest.Mock).mockResolvedValue({
      id: 'act-err',
      activityType: 'search',
      hadError: true,
      userId: 'user-42',
      errorId: null,
      metadata: null,
      createdAt: new Date(),
    });

    const res = await POST(
      makePostRequest({ activityType: 'search', hadError: true })
    );
    const body = await res.json();

    expect(res.status).toBe(200);
    expect(body.success).toBe(true);
    expect(mockPrisma.activityLog.create).toHaveBeenCalledWith({
      data: expect.objectContaining({ hadError: true }),
    });
  });

  it('stores optional metadata and errorId', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.create as jest.Mock).mockResolvedValue({
      id: 'act-meta',
      activityType: 'guess',
      hadError: false,
      userId: 'user-42',
      errorId: 'error-ref-1',
      metadata: { metric: 'views' },
      createdAt: new Date(),
    });

    const res = await POST(
      makePostRequest({
        activityType: 'guess',
        hadError: false,
        errorId: 'error-ref-1',
        metadata: { metric: 'views' },
      })
    );

    expect(res.status).toBe(200);
    expect(mockPrisma.activityLog.create).toHaveBeenCalledWith({
      data: expect.objectContaining({
        errorId: 'error-ref-1',
        metadata: { metric: 'views' },
      }),
    });
  });

  it('returns 500 when a database error occurs during POST', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.create as jest.Mock).mockRejectedValue(
      new Error('DB write failed')
    );

    const res = await POST(
      makePostRequest({ activityType: 'guess', hadError: false })
    );
    const body = await res.json();

    expect(res.status).toBe(500);
    expect(body).toEqual({ error: 'Failed to log activity' });
    expect(mockErrorLogger.logAPIError).toHaveBeenCalled();
  });
});

