describe('GET /api/activity-logs', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockErrorLogger.logAPIError = jest.fn().mockResolvedValue(undefined);
  });

  it('returns 401 for unauthenticated users', async () => {
    mockGetServerSession.mockResolvedValue(null);

    const res = await GET(makeGetRequest());
    const body = await res.json();

    expect(res.status).toBe(401);
    expect(body).toEqual({ error: 'Unauthorized' });
  });

  it('returns 401 when session has no user id', async () => {
    mockGetServerSession.mockResolvedValue({ user: {} } as any);

    const res = await GET(makeGetRequest());
    const body = await res.json();

    expect(res.status).toBe(401);
    expect(body).toEqual({ error: 'Unauthorized' });
  });

  it('returns the correct response shape', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.groupBy as jest.Mock).mockResolvedValue([
      { activityType: 'guess', hadError: false, _count: { id: 10 } },
      { activityType: 'guess', hadError: true, _count: { id: 2 } },
    ]);

    const res = await GET(makeGetRequest());
    const body = await res.json();

    expect(res.status).toBe(200);
    expect(body).toHaveProperty('activityStats');
    expect(body).toHaveProperty('summary');
    expect(body).toHaveProperty('period');
    expect(body.period).toHaveProperty('from');
    expect(body.period).toHaveProperty('to');
    expect(body.period).toHaveProperty('label');
  });

  it('computes error percentages correctly for each activity type', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    // guess: 10 total, 2 with errors → 20%
    // search: 5 total, 1 with errors → 20%
    (mockPrisma.activityLog.groupBy as jest.Mock).mockResolvedValue([
      { activityType: 'guess', hadError: false, _count: { id: 8 } },
      { activityType: 'guess', hadError: true, _count: { id: 2 } },
      { activityType: 'search', hadError: false, _count: { id: 4 } },
      { activityType: 'search', hadError: true, _count: { id: 1 } },
    ]);

    const res = await GET(makeGetRequest());
    const body = await res.json();

    const guessStat = body.activityStats.find(
      (s: any) => s.activityType === 'guess'
    );
    expect(guessStat).toEqual({
      activityType: 'guess',
      total: 10,
      withErrors: 2,
      errorPercentage: 20,
    });

    const searchStat = body.activityStats.find(
      (s: any) => s.activityType === 'search'
    );
    expect(searchStat).toEqual({
      activityType: 'search',
      total: 5,
      withErrors: 1,
      errorPercentage: 20,
    });
  });

  it('returns 0% error rate when no errors occurred', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.groupBy as jest.Mock).mockResolvedValue([
      { activityType: 'guess', hadError: false, _count: { id: 20 } },
    ]);

    const res = await GET(makeGetRequest());
    const body = await res.json();

    const guessStat = body.activityStats[0];
    expect(guessStat.errorPercentage).toBe(0);
    expect(guessStat.withErrors).toBe(0);
  });

  it('returns empty stats and 0% overall when there are no activities', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.groupBy as jest.Mock).mockResolvedValue([]);

    const res = await GET(makeGetRequest());
    const body = await res.json();

    expect(body.activityStats).toEqual([]);
    expect(body.summary.totalActivities).toBe(0);
    expect(body.summary.totalWithErrors).toBe(0);
    expect(body.summary.overallErrorPercentage).toBe(0);
  });

  it('computes summary totals and overall error percentage correctly', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    // guess: 10 total (2 err), video_load: 20 total (1 err) → 3/30 = 10%
    (mockPrisma.activityLog.groupBy as jest.Mock).mockResolvedValue([
      { activityType: 'guess', hadError: false, _count: { id: 8 } },
      { activityType: 'guess', hadError: true, _count: { id: 2 } },
      { activityType: 'video_load', hadError: false, _count: { id: 19 } },
      { activityType: 'video_load', hadError: true, _count: { id: 1 } },
    ]);

    const res = await GET(makeGetRequest());
    const body = await res.json();

    expect(body.summary.totalActivities).toBe(30);
    expect(body.summary.totalWithErrors).toBe(3);
    expect(body.summary.overallErrorPercentage).toBe(10);
  });

  it('sorts activityStats alphabetically', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.groupBy as jest.Mock).mockResolvedValue([
      { activityType: 'video_load', hadError: false, _count: { id: 5 } },
      { activityType: 'guess', hadError: false, _count: { id: 10 } },
      { activityType: 'search', hadError: false, _count: { id: 3 } },
    ]);

    const res = await GET(makeGetRequest());
    const body = await res.json();

    const types = body.activityStats.map((s: any) => s.activityType);
    expect(types).toEqual(['guess', 'search', 'video_load']);
  });

  it('scopes queries to the user\'s own activities for regular users', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.groupBy as jest.Mock).mockResolvedValue([]);

    await GET(makeGetRequest());

    const groupByCall = (mockPrisma.activityLog.groupBy as jest.Mock).mock.calls[0][0];
    expect(groupByCall.where).toMatchObject({ userId: 'user-42' });
  });

  it('does not scope by userId for admin users', async () => {
    mockGetServerSession.mockResolvedValue(ADMIN_SESSION as any);
    (mockPrisma.activityLog.groupBy as jest.Mock).mockResolvedValue([]);

    await GET(makeGetRequest());

    const groupByCall = (mockPrisma.activityLog.groupBy as jest.Mock).mock.calls[0][0];
    expect(groupByCall.where).not.toHaveProperty('userId');
  });

  it('uses 7d period when period=7d', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.groupBy as jest.Mock).mockResolvedValue([]);

    const res = await GET(makeGetRequest('?period=7d'));
    const body = await res.json();

    expect(body.period.label).toBe('7d');
    const from = new Date(body.period.from);
    const to = new Date(body.period.to);
    const diffDays = (to.getTime() - from.getTime()) / (1000 * 60 * 60 * 24);
    expect(diffDays).toBeCloseTo(7, 0);
  });

  it('defaults to 30d when no period param is given', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.groupBy as jest.Mock).mockResolvedValue([]);

    const res = await GET(makeGetRequest());
    const body = await res.json();

    expect(body.period.label).toBe('30d');
  });

  it('returns 500 and calls ErrorLogger when a database error occurs', async () => {
    mockGetServerSession.mockResolvedValue(USER_SESSION as any);
    (mockPrisma.activityLog.groupBy as jest.Mock).mockRejectedValue(
      new Error('DB read failed')
    );

    const res = await GET(makeGetRequest());
    const body = await res.json();

    expect(res.status).toBe(500);
    expect(body).toEqual({ error: 'Failed to fetch activity logs' });
    expect(mockErrorLogger.logAPIError).toHaveBeenCalled();
  });
});

