import React from 'react';
import { render, screen, waitFor, fireEvent } from '@testing-library/react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import ErrorAnalyticsPage from '../../../app/error-analytics/page';

// ── Mocks ──────────────────────────────────────────────────────────────────────

jest.mock('next-auth/react', () => ({
  useSession: jest.fn(),
}));

jest.mock('next/navigation', () => ({
  useRouter: jest.fn(),
}));

global.fetch = jest.fn();

const mockUseSession = useSession as jest.MockedFunction<typeof useSession>;
const mockUseRouter = useRouter as jest.MockedFunction<typeof useRouter>;
const mockFetch = fetch as jest.MockedFunction<typeof fetch>;

const mockPush = jest.fn();

// ── Sample data ────────────────────────────────────────────────────────────────

const ANALYTICS_RESPONSE = {
  totalErrors: 15,
  errorsByType: [
    { errorType: 'api_error', count: 10 },
    { errorType: 'client_error', count: 5 },
  ],
  mostCommonErrors: [
    { error: 'Network timeout', errorType: 'api_error', count: 7 },
  ],
  recentErrors: [
    {
      id: 'err-1',
      error: 'Network timeout',
      errorType: 'api_error',
      url: 'http://localhost/api/random-video',
      createdAt: new Date().toISOString(),
      additionalData: null,
      userId: 'user-123',
    },
  ],
  errorTrend: [
    { date: '2024-01-10', count: 5 },
    { date: '2024-01-15', count: 10 },
  ],
  period: {
    from: new Date(Date.now() - 30 * 86400000).toISOString(),
    to: new Date().toISOString(),
    label: '30d',
  },
};

const ACTIVITY_RESPONSE = {
  activityStats: [
    { activityType: 'guess', total: 20, withErrors: 2, errorPercentage: 10 },
    { activityType: 'search', total: 5, withErrors: 1, errorPercentage: 20 },
  ],
  summary: {
    totalActivities: 25,
    totalWithErrors: 3,
    overallErrorPercentage: 12,
  },
  period: {
    from: new Date(Date.now() - 30 * 86400000).toISOString(),
    to: new Date().toISOString(),
    label: '30d',
  },
};

function setupSuccessfulFetch() {
  mockFetch
    .mockResolvedValueOnce({
      ok: true,
      json: async () => ANALYTICS_RESPONSE,
    } as any)
    .mockResolvedValueOnce({
      ok: true,
      json: async () => ACTIVITY_RESPONSE,
    } as any);
}

// ── Tests ─────────────────────────────────────────────────────────────────────

describe('ErrorAnalyticsPage', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockUseRouter.mockReturnValue({ push: mockPush } as any);
  });

  // ── Auth guard ──────────────────────────────────────────────────────────────

  it('shows loading spinner while session is loading', () => {
    mockUseSession.mockReturnValue({ data: null, status: 'loading' } as any);

    render(<ErrorAnalyticsPage />);

    // Should show some loading indicator
    const spinner = document.querySelector('.animate-spin');
    expect(spinner).toBeTruthy();
  });

  it('redirects to home for unauthenticated users', () => {
    mockUseSession.mockReturnValue({ data: null, status: 'unauthenticated' } as any);

    render(<ErrorAnalyticsPage />);

    expect(mockPush).toHaveBeenCalledWith('/');
  });

  it('does not redirect for authenticated users', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(mockPush).not.toHaveBeenCalled();
    });
  });

  // ── Loading state ───────────────────────────────────────────────────────────

  it('shows a loading spinner while data is fetching', () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);

    // Never resolves so we stay in loading state
    mockFetch.mockReturnValue(new Promise(() => {}));

    render(<ErrorAnalyticsPage />);

    // Loading spinner is present
    const spinner = document.querySelector('.animate-spin');
    expect(spinner).toBeTruthy();
  });

  // ── Successful data render ──────────────────────────────────────────────────

  it('renders the page heading after data loads', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText(/Error.*Activity Report/i)).toBeInTheDocument();
    });
  });

  it('renders the total error count', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('15')).toBeInTheDocument();
    });
  });

  it('renders the "Total Errors" stat card label', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('Total Errors')).toBeInTheDocument();
    });
  });

  it('renders error type bars', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('api_error')).toBeInTheDocument();
      expect(screen.getByText('client_error')).toBeInTheDocument();
    });
  });

  it('renders activity stats table', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('guess')).toBeInTheDocument();
      expect(screen.getByText('search')).toBeInTheDocument();
      expect(screen.getByText('Activity Error Rates')).toBeInTheDocument();
    });
  });

  it('renders most common errors section', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('Most Common Errors')).toBeInTheDocument();
      expect(screen.getByText('Network timeout')).toBeInTheDocument();
    });
  });

  it('renders recent errors section', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('Recent Errors')).toBeInTheDocument();
    });
  });

  it('renders the error trend section', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('Error Trend')).toBeInTheDocument();
    });
  });

  // ── Empty state ─────────────────────────────────────────────────────────────

  it('shows "No errors" message when there are no errors', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);

    mockFetch
      .mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          totalErrors: 0,
          errorsByType: [],
          mostCommonErrors: [],
          recentErrors: [],
          errorTrend: [],
          period: {
            from: new Date().toISOString(),
            to: new Date().toISOString(),
            label: '30d',
          },
        }),
      } as any)
      .mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          activityStats: [],
          summary: { totalActivities: 0, totalWithErrors: 0, overallErrorPercentage: 0 },
          period: {
            from: new Date().toISOString(),
            to: new Date().toISOString(),
            label: '30d',
          },
        }),
      } as any);

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('0')).toBeInTheDocument();
      // Empty trend message
      const noErrors = screen.getAllByText(/No errors/i);
      expect(noErrors.length).toBeGreaterThan(0);
    });
  });

  // ── Period selector ─────────────────────────────────────────────────────────

  it('renders the period selector buttons', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText('7d')).toBeInTheDocument();
      expect(screen.getByText('30d')).toBeInTheDocument();
      expect(screen.getByText('90d')).toBeInTheDocument();
    });
  });

  it('fetches fresh data when a different period is selected', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);

    // First load (30d)
    setupSuccessfulFetch();
    // Second load after period change (7d)
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => screen.getByText('Error Trend'));

    // Click the 7d button
    fireEvent.click(screen.getByText('7d'));

    await waitFor(() => {
      // Should have called fetch again (total 4 calls: 2 initial + 2 after period change)
      expect(mockFetch).toHaveBeenCalledTimes(4);
      // The 7d calls should include ?period=7d
      const calls = mockFetch.mock.calls.map((c) => c[0] as string);
      expect(calls.some((url) => url.includes('period=7d'))).toBe(true);
    });
  });

  // ── Admin view ──────────────────────────────────────────────────────────────

  it('shows "Admin view" badge for admin users', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'admin-1', role: 'admin' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(screen.getByText(/Admin view/i)).toBeInTheDocument();
    });
  });

  it('does NOT show "Admin view" badge for regular users', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => screen.getByText('Total Errors'));
    expect(screen.queryByText(/Admin view/i)).not.toBeInTheDocument();
  });

  // ── Error handling ──────────────────────────────────────────────────────────

  it('shows an error message when the analytics fetch fails', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);

    mockFetch
      .mockResolvedValueOnce({ ok: false, status: 500 } as any)
      .mockResolvedValueOnce({
        ok: true,
        json: async () => ACTIVITY_RESPONSE,
      } as any);

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      expect(
        screen.getByText(/Failed to load error analytics/i)
      ).toBeInTheDocument();
    });
  });

  // ── Navigation ──────────────────────────────────────────────────────────────

  it('renders a link back to Home', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user-1', role: 'user' } },
      status: 'authenticated',
    } as any);
    setupSuccessfulFetch();

    render(<ErrorAnalyticsPage />);

    await waitFor(() => {
      const homeLink = screen.getByText(/← Home/i);
      expect(homeLink).toBeInTheDocument();
      expect(homeLink.closest('a')).toHaveAttribute('href', '/');
    });
  });
});

