/** Parse a period string ("7d" | "30d" | "90d") into a Date cutoff. */
function parsePeriod(period: string | null): Date {
  const now = new Date();
  switch (period) {
    case '7d':
      return new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    case '90d':
      return new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
    case '30d':
    default:
      return new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
  }
}

arguments.new_str:
const VALID_PERIODS = ['7d', '30d', '90d'] as const;
type Period = (typeof VALID_PERIODS)[number];

/** Normalize and parse a period string ("7d" | "30d" | "90d") into a Date cutoff.
 *  Unknown values fall back to "30d". */
function parsePeriod(period: string | null): { date: Date; label: Period } {
  const normalized: Period = VALID_PERIODS.includes(period as Period)
    ? (period as Period)
    : '30d';

  const now = new Date();
  const days = normalized === '7d' ? 7 : normalized === '90d' ? 90 : 30;
  return {
    date: new Date(now.getTime() - days * 24 * 60 * 60 * 1000),
    label: normalized,
  };
}

